export class OrderSummaryQuery {
  execute(orderId: string) {
    return this.http.get<OrderSummaryView>(`/orders/${orderId}/summary`);
  }
}

export class OrderTimelineQuery {
  execute(orderId: string) {
    return this.http.get<OrderEventView[]>(`/orders/${orderId}/timeline`);
  }
}

export class CancelOrderCommand {
  execute(orderId: string) {
    return this.http.post(`/orders/${orderId}/cancel`, {});
  }
}

export class PayOrderCommand {
  execute(input: PayOrderInput) {
    return this.http.post<PaymentResult>('/orders/pay', input);
  }
}

export type OrderSummaryView = {
  id: string;
  statusLabel: string;
  totalFormatted: string;
  availableActions: Array<'pay' | 'cancel' | 'reorder'>;
};

@Component({ templateUrl: './order-detail.page.html' })
export class OrderDetailPage {
  summary = inject(OrderSummaryQuery).execute(this.orderId);
  cancel = inject(CancelOrderCommand);
}
